The core challenge is partial tag matching. Build a state machine with a buffer:

```rust
pub struct StreamingToolCallParser {
    buffer: String,
    inside_tool_call: bool,
    tool_call_buffer: String,
}

impl StreamingToolCallParser {
    pub fn feed(&mut self, chunk: &str) -> Vec<StreamEvent> {
        self.buffer.push_str(chunk);
        let mut events = Vec::new();

        loop {
            if self.inside_tool_call {
                if let Some(end_pos) = self.buffer.find("</tool_call>") {
                    let body = &self.buffer[..end_pos];
                    self.tool_call_buffer.push_str(body);
                    if let Some(parsed) = self.parse_tool_call_body(&self.tool_call_buffer.clone()) {
                        events.push(StreamEvent::ToolCallComplete(parsed));
                    }
                    self.buffer = self.buffer[end_pos + "</tool_call>".len()..].to_string();
                    self.inside_tool_call = false;
                    self.tool_call_buffer.clear();
                } else {
                    let safe_len = self.safe_emit_len("</tool_call>");
                    if safe_len > 0 {
                        let emittable = self.buffer[..safe_len].to_string();
                        self.tool_call_buffer.push_str(&emittable);
                        events.push(StreamEvent::ToolCallPartial(emittable));
                        self.buffer = self.buffer[safe_len..].to_string();
                    }
                    break;
                }
            } else {
                // Look for <tool_call> opening tag...
            }
        }
        events
    }
}
```

The critical function is `safe_emit_len`: it checks every suffix of the buffer against every prefix of the target tag. If the buffer ends with `"<tool_"`, that might be the start of `"<tool_call>"`, so you hold those bytes back. Always provide a `flush()` method for stream end to emit any remaining buffered content.

```rust
pub struct BashTool {
    cwd: Mutex<Option<PathBuf>>,
}

impl Tool for BashTool {
    fn execute(&self, params: Value, ctx: &ToolContext)
        -> Pin<Box<dyn Future<Output = Result<ToolResult>> + Send + '_>>
    {
        let command = params["command"].as_str().unwrap_or("").to_string();
        let timeout_ms = params["timeout_ms"].as_u64().unwrap_or(120_000).min(600_000);
        let project_path = ctx.cwd.clone();

        Box::pin(async move {
            if command.is_empty() {
                return Ok(ToolResult::error("No command provided"));
            }

            let working_dir = {
                let guard = self.cwd.lock().unwrap();
                guard.clone().unwrap_or(project_path)
            };

            let (shell, args) = if cfg!(windows) {
                ("cmd.exe", &["/C"][..])
            } else {
                ("bash", &["-c"][..])
            };

            let mut cmd = Command::new(shell);
            for arg in args { cmd.arg(arg); }
            cmd.arg(&command).current_dir(&working_dir)
                .stdout(Stdio::piped()).stderr(Stdio::piped());

            let result = timeout(Duration::from_millis(timeout_ms), cmd.output()).await;

            match result {
                Ok(Ok(output)) => {
                    // Track cd commands to persist working directory
                    if command.starts_with("cd ") {
                        let dir = command.trim_start_matches("cd ").trim();
                        let new_dir = if dir.starts_with('/') {
                            PathBuf::from(dir)
                        } else {
                            working_dir.join(dir)
                        };
                        if new_dir.exists() {
                            *self.cwd.lock().unwrap() = Some(new_dir);
                        }
                    }
                    // Build result from stdout + stderr...
                }
                Ok(Err(e)) => Ok(ToolResult::error(format!("Failed to execute: {e}"))),
                Err(_) => Ok(ToolResult::error(format!("Command timed out after {timeout_ms}ms"))),
            }
        })
    }
}
```

Design notes: (1) Never panic on tool errors -- return `ToolResult::error` so the model can retry. (2) The `cwd` mutex tracks directory changes across calls. (3) The timeout cap at 600s prevents runaway processes. (4) Use `Stdio::piped()` for both stdout/stderr to capture all output.

For cancellation, spawn the child process and poll both the output stream and a cancellation token:

```rust
fn execute_with_cancel(&self, params: Value, ctx: &ToolContext, cancel: &CancelToken,
    progress: Option<mpsc::Sender<ToolProgress>>,
) -> Pin<Box<dyn Future<Output = Result<ToolResult>> + Send + '_>> {
    let cancel_rx = cancel.clone_receiver();
    Box::pin(async move {
        let mut child = cmd.spawn()?;
        let stdout = child.stdout.take();
        let mut collected = String::new();

        if let Some(out) = stdout {
            let mut reader = BufReader::new(out).lines();
            let deadline = Instant::now() + Duration::from_millis(timeout_ms);

            loop {
                if *cancel_rx.borrow() {
                    let _ = child.kill().await;
                    return Ok(ToolResult::error("Cancelled by user"));
                }

                let line_result = tokio::select! {
                    line = reader.next_line() => line,
                    _ = tokio::time::sleep_until(deadline) => {
                        let _ = child.kill().await;
                        return Ok(ToolResult::error("Timed out"));
                    }
                };

                match line_result {
                    Ok(Some(line)) => {
                        if let Some(ref tx) = progress {
                            let _ = tx.try_send(ToolProgress::PartialOutput(line.clone()));
                        }
                        collected.push_str(&line);
                        collected.push('\n');
                    }
                    Ok(None) => break,
                    Err(e) => { /* handle read error */ break; }
                }
            }
        }
        // Wait for exit status and build final result...
    })
}
```

The `tokio::select!` gives you three-way racing: next line vs timeout vs cancellation check. Progress messages use `try_send` (non-blocking) so a slow UI never blocks the process. Kill the child on both timeout and cancel paths.

Three components: the tool definition (so the model can request spawning), validation, and tool filtering.

```rust
pub const SUBAGENT_SYSTEM_PROMPT: &str = "\
You are a focused subagent. Complete the task thoroughly and provide a clear summary. \
Do not ask questions -- work autonomously.";

pub const SUBAGENT_MAX_ITERATIONS: usize = 30;

pub fn validate_params(params: &Value) -> Option<String> {
    let task = params["task"].as_str().unwrap_or("");
    if task.is_empty() { return Some("Missing required parameter: task".into()); }
    if task.len() > 10_000 { return Some("Task too long".into()); }
    if task.contains('\0') { return Some("Null bytes not allowed".into()); }

    if let Some(tools) = params["tools"].as_array() {
        for t in tools {
            if let Some(name) = t.as_str() {
                if name == "agent_spawn" {
                    return Some("Recursion not allowed".into());
                }
                if name.contains('/') || name.contains("..") {
                    return Some(format!("Invalid tool name: {name}"));
                }
            }
        }
    }
    None
}

pub fn filter_tools(all_tools: &[ToolDefinition], requested: Option<&[String]>) -> Vec<ToolDefinition> {
    all_tools.iter().filter(|t| {
        if t.name == "agent_spawn" { return false; } // Always exclude
        if let Some(req) = requested {
            return req.iter().any(|r| r == &t.name);
        }
        true
    }).cloned().collect()
}
```

Security invariants: (1) `agent_spawn` is always stripped from subagent tools to prevent recursion bombs. (2) Tool names are validated against path traversal. (3) Task length is capped to prevent context stuffing. (4) The subagent gets a fresh message history (no parent context leakage). (5) Execution is handled as a special case in the agent loop, not by the tool's `execute()` method.

Use Swift's structured concurrency with `withCheckedThrowingContinuation` for request/response correlation:

```swift
public actor MCPClient {
    private var requestId: Int = 0
    private var pendingRequests: [Int: CheckedContinuation<JSONRPCResponse, Error>] = [:]

    public func sendRequest(method: String, params: [String: AnyCodable]? = nil) async throws -> JSONRPCResponse {
        guard transport.isConnected else { throw MCPError.notConnected }

        requestId += 1
        let id = requestId
        let request = JSONRPCRequest(id: id, method: method, params: params)
        let data = try request.encodeToLine()
        try await transport.send(data)

        return try await withTimeout(seconds: config.requestTimeout) {
            try await withCheckedThrowingContinuation { continuation in
                self.pendingRequests[id] = continuation
            }
        }
    }

    private func handleReceivedData(_ data: Data) {
        let response = try decoder.decode(JSONRPCResponse.self, from: data)
        if let id = response.id,
           let continuation = pendingRequests.removeValue(forKey: id) {
            continuation.resume(returning: response)
        }
    }

    private func withTimeout<T>(seconds: TimeInterval, operation: @escaping () async throws -> T) async throws -> T {
        try await withThrowingTaskGroup(of: T.self) { group in
            group.addTask { try await operation() }
            group.addTask {
                try await Task.sleep(nanoseconds: UInt64(seconds * 1_000_000_000))
                throw MCPError.timeout
            }
            guard let result = try await group.next() else { throw MCPError.timeout }
            group.cancelAll()
            return result
        }
    }
}
```

The actor isolation ensures thread-safe access to `pendingRequests`. The timeout races the actual operation against a sleep task, cancelling the loser.

Guard each API call on the server's declared capabilities:

```swift
public func listTools() async throws -> [MCPTool] {
    guard isConnected else { throw MCPError.notConnected }
    guard serverCapabilities?.supportsTools == true else {
        throw MCPError.capabilityNotSupported("tools")
    }
    let response = try await sendRequest(method: "tools/list")
    let result: MCPToolListResult = try response.decodeResult(as: MCPToolListResult.self)
    return result.tools
}

public func callTool(name: String, arguments: [String: Any] = [:]) async throws -> MCPToolResult {
    guard isConnected else { throw MCPError.notConnected }
    guard serverCapabilities?.supportsTools == true else {
        throw MCPError.capabilityNotSupported("tools")
    }
    let response = try await sendRequest(method: "tools/call", params: [
        "name": AnyCodable(name),
        "arguments": AnyCodable(arguments)
    ])
    return try response.decodeResult(as: MCPToolResult.self)
}
```

This pattern applies to resources and prompts too. The capabilities are discovered during the initialization handshake (`initialize` method) and cached on the client. Benefits: (1) Fast-fail before network round-trip if the server doesn't support a feature. (2) Clear error messages for the agent loop to handle. (3) The guard pattern is uniform across all MCP APIs.

Layer three levels of health checking: simple ping, boolean healthy check, and detailed result:

```swift
public func ping() async throws -> Bool {
    guard transport.isConnected else { throw MCPError.notConnected }
    let response = try await sendRequest(method: "ping")
    return response.isSuccess || response.result != nil
}

public func isHealthy() async -> Bool {
    guard isConnected else { return false }
    do {
        return try await ping()
    } catch {
        return false
    }
}

public func healthCheck(timeout: TimeInterval = 5.0) async -> HealthCheckResult {
    guard transport.isConnected else {
        return HealthCheckResult(isHealthy: false, latencyMs: nil, error: "Not connected")
    }
    let startTime = Date()
    do {
        _ = try await withTimeout(seconds: timeout) { try await self.ping() }
        let latencyMs = Date().timeIntervalSince(startTime) * 1000
        return HealthCheckResult(isHealthy: true, latencyMs: latencyMs, error: nil)
    } catch {
        return HealthCheckResult(isHealthy: false, latencyMs: nil, error: error.localizedDescription)
    }
}
```

The three tiers serve different callers: `ping()` for programmatic checks that want to handle errors, `isHealthy()` for simple boolean guards, and `healthCheck()` for UI display with latency metrics.

