    let task = Task<VATokens, Error> { /* actual HTTP refresh */ }
    refreshTask = task
    defer { refreshTask = nil }
    return try await task.value
}
```

This pattern ensures: (1) No unnecessary token refreshes. (2) No race conditions on concurrent API calls. (3) The 5-minute buffer gives plenty of time for the refresh round-trip before the old token actually expires.

Use Security framework directly with `kSecClassGenericPassword`:

```swift
private func saveToKeychain(key: String, value: String) {
    let data = value.data(using: .utf8)!
    let query: [String: Any] = [
        kSecClass as String: kSecClassGenericPassword,
        kSecAttrAccount as String: key,
        kSecAttrService as String: "com.myapp.auth"
    ]
    SecItemDelete(query as CFDictionary)  // Delete existing first
    var addQuery = query
    addQuery[kSecValueData as String] = data
    SecItemAdd(addQuery as CFDictionary, nil)
}

private func loadFromKeychain(key: String) -> String? {
    let query: [String: Any] = [
        kSecClass as String: kSecClassGenericPassword,
        kSecAttrAccount as String: key,
        kSecAttrService as String: "com.myapp.auth",
        kSecReturnData as String: true,
        kSecMatchLimit as String: kSecMatchLimitOne
    ]
    var result: AnyObject?
    let status = SecItemCopyMatching(query as CFDictionary, &result)
    guard status == errSecSuccess, let data = result as? Data else { return nil }
    return String(data: data, encoding: .utf8)
}
```

