Use `@Published` properties for SwiftUI binding and an async token stream:

```swift
@MainActor
public class ChatManager: ObservableObject {
    @Published public var streamingResponse: String = ""
    @Published public var isStreaming: Bool = false

    func processStreamingResponse(stream: AsyncStream<String>) async {
        isStreaming = true
        streamingResponse = ""

        for await token in stream {
            streamingResponse += token
        }

        // Stream complete -- finalize the message
        let finalContent = streamingResponse
        streamingResponse = ""
        isStreaming = false

        // Append to conversation
        var conversation = currentConversation!
        conversation.messages.append(Message(content: finalContent, role: .assistant))
        currentConversation = conversation
    }
}
```

