The MCP protocol requires a three-step handshake: start transport, send `initialize`, then send `notifications/initialized`.

```swift
public func connect() async throws {
    // Step 1: Start the underlying transport (stdio, HTTP, etc.)
    try await transport.start()
    startReceiving()  // Begin listening for responses

    // Step 2: Send initialize request with client capabilities
    let initParams = MCPInitializeParams()
    let response = try await sendRequest(method: "initialize", params: [
        "protocolVersion": AnyCodable(initParams.protocolVersion),
        "capabilities": AnyCodable([String: Any]()),
        "clientInfo": AnyCodable([
            "name": initParams.clientInfo.name,
            "version": initParams.clientInfo.version
        ])
    ])

    // Parse server capabilities for later use
    let result: MCPInitializeResult = try response.decodeResult(as: MCPInitializeResult.self)
    serverCapabilities = result.capabilities
    serverInfo = result.serverInfo

    // Step 3: Notify server that initialization is complete
    try await sendNotification(method: "notifications/initialized")
    isInitialized = true
}
```

