```rust
fn convert_to_anthropic(&self, request: &ChatRequest) -> (Option<String>, Vec<serde_json::Value>) {
    let mut system = None;
    let mut messages = Vec::new();
    for msg in &request.messages {
        match msg.role {
            Role::System => { system = Some(msg.content.clone()); }
            Role::User => {
                messages.push(json!({"role": "user", "content": msg.content}));
            }
            Role::Assistant => {
